import React from 'react';

const experiences = [
  {
    role: 'Computer Science Student',
    company: 'University/College',
    desc: 'Currently in my second year, focusing on full-stack development and exploring Machine Learning. Building projects to apply theoretical knowledge and develop practical skills.',
    period: '2023 – Present'
  },
  {
    role: 'Self-Learning Developer',
    company: 'Personal Projects',
    desc: 'Continuously learning new technologies through online courses, tutorials, and hands-on projects. Building responsive web applications and experimenting with ML algorithms.',
    period: '2022 – Present'
  },
  {
    role: 'Coding Enthusiast',
    company: 'Open Source & Practice',
    desc: 'Started my coding journey with basic web development. Gradually expanded skills to include modern frameworks, databases, and exploring the exciting world of Machine Learning.',
    period: '2021 – 2022'
  }
];

const Experience = () => {
  return (
    <section id="experience">
      <div className="exp-inner">
        <div className="reveal">
          <div className="section-label">
            <span className="section-label-line"></span>
            <span>Experience</span>
          </div>
          <h2 className="section-title">My Learning<br /><em>Journey</em></h2>
          <p style={{marginTop:'24px', color:'var(--muted)', fontSize:'0.9rem', lineHeight:'1.9', maxWidth:'280px'}}>
            From curious beginner to passionate developer. Each step in my learning journey has shaped my skills and fueled my passion for technology.
          </p>
        </div>

        <div className="exp-list reveal-stagger">
          {experiences.map((exp, index) => (
            <div key={index} className="exp-item">
              <div>
                <div className="exp-role">{exp.role}</div>
                <div className="exp-company">{exp.company}</div>
                <p className="exp-desc">{exp.desc}</p>
              </div>
              <div className="exp-period">{exp.period}</div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Experience;
